			"label": "Month and year",
			"description": "Provides the month and year; e.g., 'January 2013', but not 'jan13'",
			"type": "string",
			"autovalue": "{{subst:CURRENTMONTHNAME}} {{subst:CURRENTYEAR}}",
			"suggested": true
		}
	}
}
